// Your raw JSON string (exactly as given)
const raw = $input.first().json.intermediateSteps;

// 1. Parse the JSON string into a JS value
const arr = JSON.parse(raw);

// 2. In your example, it's an array with a single object
const obj = arr[0];

// 3. Extract top-level fields
const query = obj.query;
const followUpQuestions = obj.follow_up_questions;
const answer = obj.answer;
const responseTime = obj.response_time;
const requestId = obj.request_id;

// 4. Extract the results in a convenient format (e.g., list of papers)
const hasResults = Array.isArray(obj.results);
const results = hasResults ? obj.results.map(r => ({
  url: r.url,
  title: r.title,
  content: r.content,
  score: r.score,
})) : [];

const outputItems = hasResults ? obj.results.map(r => ({
  json: {
    query: obj.query,
    follow_up_questions: obj.follow_up_questions,
    answer: obj.answer,
    response_time: obj.response_time,
    request_id: obj.request_id,
    url: r.url,
    title: r.title,
    content: r.content,
    score: r.score,
  },
})) : [{
  json: {
    query: obj.query,
    follow_up_questions: obj.follow_up_questions,
    answer: obj.answer,
    response_time: obj.response_time,
    request_id: obj.request_id,
    results: [],
    warning: "No results found."
  }
}];

return outputItems;

const files = $input.all().at(0)?.binary
const isFilesSent = typeof files === 'object' && Object.keys(files)?.length

if (isFilesSent) {
  return {files}
}

return $input.all()

// Loop over all input items
for (const item of $input.all()) {

  // Check if binary data exists
  if (item.binary) {

    // Loop through all binary keys (e.g., 'data', 'file')
    for (const key of Object.keys(item.binary)) {
      const binaryFile = item.binary[key];

      // Check if it looks like a docx (by name or extension)
      const isDocx = (binaryFile.fileName && binaryFile.fileName.toLowerCase().endsWith('.docx')) || 
                     (binaryFile.fileExtension && binaryFile.fileExtension.toLowerCase() === 'docx');

      if (isDocx) {

        // 1. Save original name to JSON for reference
        item.json.original_filename = binaryFile.fileName;

        // 2. RE-CREATE the binary object to ensure n8n sees the change
        // We copy all existing data (...binaryFile) but overwrite the identifiers
        item.binary[key] = {
          ...binaryFile,
          fileName: 'temp_converted.zip',
          fileExtension: 'zip',
          mimeType: 'application/zip',
          fileType: 'zip'
        };
      }
    }
  }
}

return $input.all();

// Loop over input items
// We use a standard for-loop to allow 'await' inside if supported by your n8n version
const results = [];
const items = $input.all();

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  let xmlContent = null;
  let filenameFound = "None";
  let extractionMethod = "None";
  let errorLog = [];
  let binaryData = null;

  // 1. FIND THE CORRECT BINARY FILE
  if (item.binary) {
    for (const key of Object.keys(item.binary)) {
      const binaryFile = item.binary[key];
      const fname = binaryFile.fileName || "";

      // Check for document.xml
      if (fname.endsWith('word/document.xml') || fname === 'document.xml') {

        // Get the data as a Buffer
        binaryData = Buffer.from(binaryFile.data, 'base64');
        filenameFound = fname;

        // FORENSICS
        const hexHeader = binaryData.subarray(0, 4).toString('hex');
        errorLog.push(`Hex Header: ${hexHeader}`);

        // CHECK: Is it still a ZIP file?
        if (hexHeader.startsWith('504b0304')) {
            errorLog.push("CRITICAL: File is still a ZIP. Compression node failed.");
            item.json.critical_error = "Output is still a ZIP.";
        } else {
            // 2. ATTEMPT DECODING

            // Try A: Standard UTF-8
            const asString = binaryData.toString('utf8').trim();
            if (asString.includes('<w:document') || asString.startsWith('<')) {
               xmlContent = asString;
               extractionMethod = "standard_utf8";
            } 
            else {
               // Try B: Native DecompressionStream (No require needed)
               // This works in Node 18+ and modern environments
               if (typeof DecompressionStream !== 'undefined') {
                   errorLog.push("Attempting native DecompressionStream...");
                   try {
                       // We wrap the buffer in a Blob/Response to get a readable stream
                       // We use 'deflate-raw' because zip contents are usually raw deflate
                       const stream = new Response(binaryData).body.pipeThrough(new DecompressionStream('deflate-raw'));
                       const blob = await new Response(stream).blob();
                       xmlContent = await blob.text();
                       extractionMethod = "native_decompression_stream";
                   } catch (err) {
                       errorLog.push(`DecompressionStream Error: ${err.message}`);

                       // Fallback: Try 'deflate' (zlib wrapped) just in case
                       try {
                           const stream2 = new Response(binaryData).body.pipeThrough(new DecompressionStream('deflate'));
                           const blob2 = await new Response(stream2).blob();
                           xmlContent = await blob2.text();
                           extractionMethod = "native_decompression_stream_zlib";
                       } catch (err2) {
                           errorLog.push(`DecompressionStream (Zlib) Error: ${err2.message}`);
                       }
                   }
               } else {
                   errorLog.push("DecompressionStream API not available in this environment.");
               }
            }
        }
        break; 
      }
    }
  }

  // 3. PARSE THE XML
  if (xmlContent && (xmlContent.includes('<w:document') || xmlContent.includes('<w:t'))) {

    // Cleanup BOM
    if (xmlContent.charCodeAt(0) === 0xFEFF) xmlContent = xmlContent.slice(1);

    item.json.debug_xml_preview = xmlContent.substring(0, 100);

    // Paragraph Parsing
    const paragraphs = xmlContent.split(/<\/w:p>/);
    const extractedLines = paragraphs.map(para => {
      const textMatches = para.match(/<w:t[\s\S]*?>([\s\S]*?)<\/w:t>/g);
      if (!textMatches) return null;
      return textMatches.map(tag => tag.replace(/<[^>]+>/g, '')).join(''); 
    });

    const cleanText = extractedLines
      .filter(line => line !== null && line.trim() !== '')
      .join('\n');

    item.json.extracted_text = cleanText || "EMPTY (Structure found but no text)";
    extractionMethod += "_structured";
  } else {
    item.json.extracted_text = "ERROR: Failed to decode.";
    item.json.debug_log = errorLog;
  }

  item.json.found_file_name = filenameFound;
  item.json.extraction_method = extractionMethod;
  results.push(item);
}

return results;

const obj = $input.first().json.output;

return Object.entries(obj).map(([id, query]) => ({
  json: { id, query }
}));

